import { useState, useEffect, useCallback } from "react";
import axios from "axios";

// Puxando as constantes da raiz da src
import { EMPTY_FORM, COLORS, SERVICES } from "./constants";

const API_URL = "http://localhost:8080/agendamento";

export default function App() {
  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingId, setEditingId] = useState(null);
  const [toast, setToast] = useState(null);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const fetchAppointments = useCallback(async () => {
    try {
      const response = await axios.get(API_URL);
      const formattedData = response.data.map(item => ({
        id: item.id,
        name: item.clienteNome,
        service: item.servico,
        date: item.dataHora.split('T')[0],
        time: item.dataHora.split('T')[1].substring(0, 5)
      }));
      setAppointments(formattedData);
    } catch (error) {
      console.error("Erro na API:", error);
    }
  }, []);

  useEffect(() => {
    fetchAppointments();
  }, [fetchAppointments]);

  return (
    <div style={{ 
      backgroundColor: COLORS?.bege || "#F5F5DC", 
      minHeight: "100vh", 
      fontFamily: "sans-serif",
      color: COLORS?.preto || "#121212",
      padding: "20px"
    }}>
      {/* HEADER SIMPLIFICADO PARA TESTE */}
      <header style={{ textAlign: 'center', marginBottom: '40px' }}>
        <h1 style={{ fontSize: '2.5rem', fontWeight: 'bold' }}>PALHETA BARBEARIA</h1>
        <p>Gerenciamento de Agendamentos</p>
      </header>

      <main style={{ maxWidth: '800px', margin: '0 auto', backgroundColor: 'white', padding: '20px', borderRadius: '8px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>

        {/* FORMULÁRIO RÁPIDO */}
        <div style={{ marginBottom: '30px' }}>
          <h3>{editingId ? "Editar Agendamento" : "Novo Agendamento"}</h3>
          <div style={{ display: 'grid', gap: '10px' }}>
            <input 
              placeholder="Nome do Cliente"
              value={form.name}
              onChange={e => setForm({...form, name: e.target.value})}
              style={{ padding: '10px', border: '1px solid #ccc' }}
            />
            <select 
              value={form.service}
              onChange={e => setForm({...form, service: e.target.value})}
              style={{ padding: '10px', border: '1px solid #ccc' }}
            >
              <option value="">Selecione um serviço</option>
              {SERVICES?.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
            <div style={{ display: 'flex', gap: '10px' }}>
              <input type="date" value={form.date} onChange={e => setForm({...form, date: e.target.value})} style={{ flex: 1, padding: '10px' }} />
              <input type="time" value={form.time} onChange={e => setForm({...form, time: e.target.value})} style={{ flex: 1, padding: '10px' }} />
            </div>
            <button style={{ backgroundColor: COLORS?.preto, color: 'white', padding: '12px', cursor: 'pointer', border: 'none' }}>
              Salvar Agendamento
            </button>
          </div>
        </div>

        {/* TABELA RÁPIDA */}
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ borderBottom: '2px solid #eee' }}>
              <th style={{ textAlign: 'left', padding: '10px' }}>Cliente</th>
              <th style={{ textAlign: 'left', padding: '10px' }}>Serviço</th>
              <th style={{ textAlign: 'left', padding: '10px' }}>Data</th>
            </tr>
          </thead>
          <tbody>
            {appointments.length > 0 ? appointments.map(appt => (
              <tr key={appt.id} style={{ borderBottom: '1px solid #eee' }}>
                <td style={{ padding: '10px' }}>{appt.name}</td>
                <td style={{ padding: '10px' }}>{appt.service}</td>
                <td style={{ padding: '10px' }}>{appt.date} às {appt.time}</td>
              </tr>
            )) : (
              <tr><td colSpan="3" style={{ padding: '20px', textAlign: 'center' }}>Nenhum agendamento encontrado.</td></tr>
            )}
          </tbody>
        </table>
      </main>

      {toast && (
        <div style={{ position: 'fixed', bottom: 20, right: 20, padding: '15px', backgroundColor: '#333', color: 'white', borderRadius: '5px' }}>
          {toast.msg}
        </div>
      )}
    </div>
  );
}
